parameters.query:
={{ (function() {
  var landscape = $('Pick Landscape').first().json.name;
  var tags = $('Pick Landscape').first().json.tags;
  var raw = $('Analyze Competitor').first().json.content ? $('Analyze Competitor').first().json.content[0].text : '[]';
  var competitors;
  try { competitors = JSON.parse(raw.replace(/```json[\s\S]*?```/g, '').replace(/```/g, '').trim()); } catch(e) { return 'SELECT 0 as inserted'; }
  if (!Array.isArray(competitors)) competitors = [competitors];

  var stmts = [];
  for (var i = 0; i < competitors.length && i < 5; i++) {
    var c = competitors[i];
    var name = (c.name || '').replace(/'/g, "''");
    var size = (c.size || 'Unknown').replace(/'/g, "''");
    var threat = (c.threat_level || 'MEDIUM').replace(/'/g, "''");
    var caps = (c.capabilities || '').replace(/'/g, "''").substring(0, 500);
    var wins = (c.recent_wins || '').replace(/'/g, "''").substring(0, 500);
    var threat_summary = (c.gda_threat_summary || '').replace(/'/g, "''").substring(0, 300);
    if (name) {
      stmts.push("INSERT INTO gda_competitor_watchlist (name, size, threat_level, capabilities, recent_contracts, landscape, tags, gda_threat_summary) SELECT '" + name + "', '" + size + "', '" + threat + "', '" + caps + "', '" + wins + "', '" + landscape + "', '" + tags + "', '" + threat_summary + "' WHERE NOT EXISTS (SELECT 1 FROM gda_competitor_watchlist WHERE LOWER(name) = LOWER('" + name + "'))");
    }
  }
  if (stmts.length === 0) return 'SELECT 0 as inserted';
  return stmts.join(';\n') + ';\nSELECT ' + stmts.length + ' as inserted';
})() }}

